"""
Network Security Model Implementation
Classifies security threats and implements countermeasures based on OSI layers
"""

from enum import Enum
from dataclasses import dataclass
from typing import List, Tuple

class ThreatType(Enum):
    INTERCEPTION = "interception"
    INTERRUPTION = "interruption"
    MODIFICATION = "modification"
    FABRICATION = "fabrication"
    NONE = "none"

class SecurityLevel(Enum):
    LOW = 1
    MEDIUM = 2
    HIGH = 3
    CRITICAL = 4

class OSILayer(Enum):
    PHYSICAL = 1
    DATA_LINK = 2
    NETWORK = 3
    TRANSPORT = 4
    SESSION = 5
    PRESENTATION = 6
    APPLICATION = 7

@dataclass
class NetworkPacket:
    """Represents a network packet with security attributes"""
    source_ip: str
    dest_ip: str
    layer: OSILayer
    mac_address: str
    port: int
    protocol: str
    payload: str
    encrypted: bool = False

@dataclass
class SecurityResult:
    """Result of security analysis"""
    threat_type: ThreatType
    threat_level: SecurityLevel
    countermeasures: List[str]
    action: str

class NetworkSecurityModel:
    """Implements the comprehensive network security model"""

    def __init__(self):
        self.threat_log = []

    def analyze_packet(self, packet: NetworkPacket) -> SecurityResult:
        """Analyze a packet and determine security measures"""

        layer = packet.layer

        if layer == OSILayer.PHYSICAL:
            return self._analyze_physical_layer(packet)
        elif layer == OSILayer.DATA_LINK:
            return self._analyze_data_link_layer(packet)
        elif layer == OSILayer.NETWORK:
            return self._analyze_network_layer(packet)
        elif layer == OSILayer.TRANSPORT:
            return self._analyze_transport_layer(packet)
        elif layer == OSILayer.SESSION:
            return self._analyze_session_layer(packet)
        elif layer == OSILayer.PRESENTATION:
            return self._analyze_presentation_layer(packet)
        else:
            return self._analyze_application_layer(packet)

    def _analyze_physical_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Physical Layer security: Interception threats"""
        return SecurityResult(
            threat_type=ThreatType.INTERCEPTION,
            threat_level=SecurityLevel.HIGH,
            countermeasures=["Secure facility access", "Lock devices", "Tamper-evident tape"],
            action="ALLOW"  # Physical security is handled externally
        )

    def _analyze_data_link_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Data Link Layer: MAC spoofing, VLAN hopping"""
        # Simulate MAC address validation
        if self._is_mac_spoofed(packet.mac_address):
            self.threat_log.append("MAC spoofing detected")
            return SecurityResult(
                threat_type=ThreatType.INTERCEPTION,
                threat_level=SecurityLevel.HIGH,
                countermeasures=["802.1X authentication", "VLAN isolation", "Port security"],
                action="BLOCK"
            )
        return SecurityResult(
            threat_type=ThreatType.NONE,
            threat_level=SecurityLevel.LOW,
            countermeasures=["802.1X", "ACLs"],
            action="ALLOW"
        )

    def _analyze_network_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Network Layer: IP spoofing, routing attacks"""
        if self._is_ip_spoofed(packet.source_ip):
            return SecurityResult(
                threat_type=ThreatType.INTERCEPTION,
                threat_level=SecurityLevel.CRITICAL,
                countermeasures=["ACL filtering", "IP verification", "Secure routing (OSPF)"],
                action="BLOCK"
            )
        return SecurityResult(
            threat_type=ThreatType.NONE,
            threat_level=SecurityLevel.LOW,
            countermeasures=["Firewall", "ACL"],
            action="ALLOW"
        )

    def _analyze_transport_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Transport Layer: SYN flooding, session hijacking"""
        if packet.protocol == "TCP" and self._detect_syn_flood(packet):
            return SecurityResult(
                threat_type=ThreatType.INTERRUPTION,
                threat_level=SecurityLevel.CRITICAL,
                countermeasures=["TLS encryption", "Firewall", "SYN cookies"],
                action="BLOCK"
            )
        return SecurityResult(
            threat_type=ThreatType.NONE,
            threat_level=SecurityLevel.LOW,
            countermeasures=["TLS", "IDS"],
            action="ALLOW"
        )

    def _analyze_session_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Session Layer: Session hijacking, cookie tampering"""
        return SecurityResult(
            threat_type=ThreatType.INTERCEPTION,
            threat_level=SecurityLevel.MEDIUM,
            countermeasures=["SSL/TLS", "Secure session management", "Cookie security"],
            action="ALLOW"
        )

    def _analyze_presentation_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Presentation Layer: Encryption, data format"""
        if not packet.encrypted:
            return SecurityResult(
                threat_type=ThreatType.INTERCEPTION,
                threat_level=SecurityLevel.MEDIUM,
                countermeasures=["AES encryption", "Secure compression", "TLS"],
                action="WARN"
            )
        return SecurityResult(
            threat_type=ThreatType.NONE,
            threat_level=SecurityLevel.LOW,
            countermeasures=["AES", "Secure formatting"],
            action="ALLOW"
        )

    def _analyze_application_layer(self, packet: NetworkPacket) -> SecurityResult:
        """Application Layer: Malware, SQL injection, XSS"""
        if "<script>" in packet.payload or "DROP TABLE" in packet.payload:
            return SecurityResult(
                threat_type=ThreatType.MODIFICATION,
                threat_level=SecurityLevel.CRITICAL,
                countermeasures=["HTTPS", "Input validation", "SQL injection prevention", "WAF"],
                action="BLOCK"
            )
        return SecurityResult(
            threat_type=ThreatType.NONE,
            threat_level=SecurityLevel.LOW,
            countermeasures=["HTTPS", "Input sanitization"],
            action="ALLOW"
        )

    def _is_mac_spoofed(self, mac: str) -> bool:
        """Simulate MAC address spoofing detection"""
        # In real implementation, compare against known valid MACs
        return mac.startswith("00:00:00")

    def _is_ip_spoofed(self, ip: str) -> bool:
        """Simulate IP spoofing detection"""
        # In real implementation, check IP against routing tables
        return ip.startswith("192.168.0.1")

    def _detect_syn_flood(self, packet: NetworkPacket) -> bool:
