# Demonstrate network segmentation
class NetworkSegmentation:
    """Implements network segmentation concept"""

    def __init__(self):
        self.segments = {
            "guest": ["192.168.1.0/24"],
            "corporate": ["10.0.0.0/24"],
            "dmz": ["172.16.0.0/24"],
            "sensitive": ["10.0.1.0/24"]
        }

    def get_segment_policy(self, segment: str) -> List[str]:
        """Return security policy for a network segment"""
        policies = {
            "guest": ["Internet access only", "No internal network access", "Bandwidth limit"],
            "corporate": ["Full internal access", "Internet via proxy", "File sharing allowed"],
            "dmz": ["Limited external access", "Web servers only", "Strict firewall rules"],
            "sensitive": ["Restricted access", "Encryption required", "Multi-factor auth"]
        }
        return policies.get(segment, ["Default policy"])

# Main demonstration
if __name__ == "__main__":
    security_model = NetworkSecurityModel()

    # Test packets at different layers
    test_packets = [
        NetworkPacket("192.168.1.100", "10.0.0.1", OSILayer.APPLICATION, 
                     "00:11:22:33:44:55", 80, "HTTP", "<script>alert('xss')</script>"),
        NetworkPacket("10.0.0.50", "10.0.0.1", OSILayer.NETWORK,
                     "00:11:22:33:44:55", 443, "TCP", "GET / HTTP/1.1"),
    ]

    for packet in test_packets:
        result = security_model.analyze_packet(packet)
        print(f"\nLayer: {packet.layer.name}")
        print(f"Threat: {result.threat_type.value}")
        print(f"Level: {result.threat_level.name}")
        print(f"Action: {result.action}")
        print(f"Countermeasures: {result.countermeasures}")

    # Demonstrate network segmentation
    seg = NetworkSegmentation()
    print("\n--- Network Segmentation ---")
    for segment in seg.segments:
        print(f"{segment}: {seg.get_segment_policy(segment)}")

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// Constants for threat levels
#define THREAT_LOW      1
#define THREAT_MEDIUM   2
#define THREAT_HIGH     3
#define THREAT_CRITICAL 4

// OSI Layer definitions
typedef enum {
    LAYER_PHYSICAL = 1,
    LAYER_DATA_LINK = 2,
    LAYER_NETWORK = 3,
    LAYER_TRANSPORT = 4,
    LAYER_SESSION = 5,
    LAYER_PRESENTATION = 6,
    LAYER_APPLICATION = 7
} OSILayer;

// Threat types from the security model
typedef enum {
    THREAT_INTERCEPTION,
    THREAT_INTERRUPTION,
    THREAT_MODIFICATION,
    THREAT_FABRICATION,
    THREAT_NONE
} ThreatType;

// Network packet structure
typedef struct {
    char source_ip[16];
    char dest_ip[16];
    int source_port;
    int dest_port;
    char protocol[10];
    OSILayer layer;
    char payload[256];
    bool encrypted;
} NetworkPacket;

// Firewall rule structure
typedef struct {
    char ip_prefix[16];
    int port;
    char protocol[10];
    bool allow;  // true = allow, false = block
} FirewallRule;

// Network segment definitions (for segmentation)
typedef struct {
    char segment_name[20];
    char ip_range[20];
    int security_level;
} NetworkSegment;

// Initialize default firewall rules
void init_firewall_rules(FirewallRule *rules, int *rule_count) {
    *rule_count = 0;

    // Block known malicious IPs
    strcpy(rules[*rule_count].ip_prefix, "192.168.0.1");
    rules[*rule_count].port = 0;  // Any port
    strcpy(rules[*rule_count].protocol, "ANY");
    rules[*rule_count].allow = false;
    (*rule_count)++;

    // Allow HTTP traffic
    strcpy(rules[*rule_count].ip_prefix, "0.0.0.0");
    rules[*rule_count].port = 80;
    strcpy(rules[*rule_count].protocol, "TCP");
    rules[*rule_count].allow = true;
    (*rule_count)++;

    // Allow HTTPS traffic
    strcpy(rules[*rule_count].ip_prefix, "0.0.0.0");
    rules[*rule_count].port = 443;
    strcpy(rules[*rule_count].protocol, "TCP");
    rules[*rule_count].allow = true;
    (*rule_count)++;

    // Block telnet (insecure)
    strcpy(rules[*rule_count].ip_prefix, "0.0.0.0");
    rules[*rule_count].port = 23;
    strcpy(rules[*rule_count].protocol, "TCP");
    rules[*rule_count].allow = false;
    (*rule_count)++;
}

// Check if IP matches a rule
bool ip_matches(const char *packet_ip, const char *rule_prefix) {
    if (strcmp(rule_prefix, "0.0.0.0") == 0) {
        return true;  // Match all
    }
    return strncmp(packet_ip, rule_prefix, strlen(rule_prefix)) == 0;
}

// Main firewall filtering function
// Returns: 1 = ALLOW, 0 = BLOCK
int filter_packet(NetworkPacket *packet, FirewallRule *rules, int rule_count) {

    printf("\n--- Analyzing Packet ---");
    printf("\nSource: %s:%d -> Dest: %s:%d", 
           packet->source_ip, packet->source_port,
           packet->dest_ip, packet->dest_port);
    printf("\nProtocol: %s | Layer: %d", packet->protocol, packet->layer);

    // Check each firewall rule
    for (int i = 0; i < rule_count; i++) {
        // Check IP prefix match
        if (!ip_matches(packet->source_ip, rules[i].ip_prefix)) {
            continue;
        }

        // Check port match (0 = any port)
        if (rules[i].port != 0 && rules[i].port != packet->dest_port) {
            continue;
        }

        // Check protocol match
        if (strcmp(rules[i].protocol, "ANY") != 0 && 
            strcmp(rules[i].protocol, packet->protocol) != 0) {
            continue;
        }

        // Rule matched - apply it
        printf("\nRule %d matched: %s", i + 1, rules[i].allow ? "ALLOW" : "BLOCK");
        return rules[i].allow ? 1 : 0;
    }

    // Default: block if no rule matches (default deny)
    printf("\nNo rule matched - DEFAULT DENY");
    return 0;
}

// Classify threat based on OSI layer
ThreatType classify_threat(NetworkPacket *packet) {
    switch (packet->layer) {
        case LAYER_PHYSICAL:
            return THREAT_INTERCEPTION;
        case LAYER_DATA_LINK:
            return THREAT_INTERCEPTION;  // MAC spoofing
        case LAYER_NETWORK:
            return THREAT_INTERCEPTION;  // IP spoofing
        case LAYER_TRANSPORT:
            return THREAT_INTERRUPTION;  // SYN flood
        case LAYER_SESSION:
            return THREAT_INTERCEPTION;  // Session hijack
        case LAYER_PRESENTATION:
            return THREAT_INTERCEPTION;  // Unencrypted
        case LAYER_APPLICATION:
            // Check payload for attacks
            if (strstr(packet->payload, "<script>") != NULL ||
                strstr(packet->payload, "DROP TABLE") != NULL) {
                return THREAT_MODIFICATION;
            }
            return THREAT_NONE;
        default:
            return THREAT_NONE;
    }
}

// Security monitoring function
void monitor_network(NetworkPacket *packets, int count, 
                     FirewallRule *rules, int rule_count) {

    printf("\n========================================");
    printf("\n   NETWORK SECURITY MONITOR");
    printf("\n========================================\n");

    int allowed = 0, blocked = 0;

    for (int i = 0; i < count; i++) {
        printf("\n[Packet %d]", i + 1);

        // First, classify the threat
        ThreatType threat = classify_threat(&packets[i]);

        // Then apply firewall rules
        int result = filter_packet(&packets[i], rules, rule_count);

        if (result) {
            allowed++;
        } else {
            blocked++;
        }

        // Display threat classification
        const char *threat_names[] = 
            {"Interception", "Interruption", "Modification", "Fabrication", "None"};
        printf("\nThreat Type: %s", threat_names[threat]);
    }

    printf("\n\n========== SUMMARY ==========");
    printf("\nTotal Packets: %d", count);
    printf("\nAllowed: %d", allowed);
    printf("\nBlocked: %d", blocked);
    printf("\n============================\n");
}

int main() {
    // Create sample network packets
    NetworkPacket packets[5];

    // Packet 1: Normal HTTPS
    strcpy(packets[0].source_ip, "192.168.1.100");
    strcpy(packets[0].dest_ip, "8.8.8.8");
    packets[0].source_port = 12345;
    packets[0].dest_port = 443;
    strcpy(packets[0].protocol, "TCP");
    packets[0].layer = LAYER_APPLICATION;
    strcpy(packets[0].payload, "GET /index.html HTTP/1.1");
    packets[0].encrypted = true;

    // Packet 2: Blocked telnet
    strcpy(packets[1].source_ip, "192.168.1.100");
    strcpy(packets[1].dest_ip, "10.0.0.1");
    packets[1].source_port = 54321;
    packets[1].dest_port = 23;
    strcpy(packets[1].protocol, "TCP");
    packets[1].layer = LAYER_APPLICATION;
    strcpy(packets[1].payload, "login: ");
    packets[1].encrypted = false;

    // Packet 3: Suspicious SQL injection
    strcpy(packets[2].source_ip, "192.168.1.200");
    strcpy(packets[2].dest_ip, "10.0.0.5");
    packets[2].source_port = 11111;
    packets[2].dest_port = 80;
    strcpy(packets[2].protocol, "TCP");
    packets[2].layer = LAYER_APPLICATION;
    strcpy(packets[2].payload, "username=' OR '1'='1; DROP TABLE users");
    packets[2].encrypted = false;

    // Packet 4: IP Spoofing attempt
    strcpy(packets[3].source_ip, "192.168.0.1");  // Known malicious
    strcpy(packets[3].dest_ip, "10.0.0.1");
    packets[3].source_port = 9999;
    packets[3].dest_port = 80;
    strcpy(packets[3].protocol, "TCP");
    packets[3].layer = LAYER_NETWORK;
    strcpy(packets[3].payload, "GET / HTTP/1.1");
    packets[3].encrypted = false;

    // Packet 5: Normal HTTP
    strcpy(packets[4].source_ip, "192.168.1.50");
    strcpy(packets[4].dest_ip, "172.16.0.1");
    packets[4].source_port = 22222;
    packets[4].dest_port = 80;
    strcpy(packets[4].protocol, "TCP");
    packets[4].layer = LAYER_APPLICATION;
    strcpy(packets[4].payload, "GET /public HTTP/1.1");
    packets[4].encrypted = false;

    // Initialize firewall rules
    FirewallRule rules[10];
    int rule_count;
    init_firewall_rules(rules, &rule_count);

    // Display firewall rules
    printf("--- FIREWALL RULES ---");
    for (int i = 0; i < rule_count; i++) {
        printf("\nRule %d: IP=%s Port=%d Protocol=%s -> %s",
               i + 1, rules[i].ip_prefix, rules[i].port, 
               rules[i].protocol, rules[i].allow ? "ALLOW" : "BLOCK");
    }

    // Monitor network
    monitor_network(packets, 5, rules, rule_count);

    return 0;
}
